        if (ql &lt;= l &amp;&amp; r &lt;= qr) return seg[id];
        int mid = (l + r) &gt;&gt; 1;
        Node res = null;
        if (ql &lt;= mid) res = merge(res, query(id &lt;&lt; 1, l, mid, ql, qr));
        if (qr &gt; mid) res = merge(res, query(id &lt;&lt; 1 | 1, mid + 1, r, ql, qr));
        return res;
    }

