def solve():
    # 使用快读提高效率
    input = sys.stdin.read().split()
    if not input:
        return

    idx = 0
    n = int(input[idx]); idx += 1
    q = int(input[idx]); idx += 1

    a = [0] * (n + 1)
    for i in range(1, n + 1):
        a[i] = int(input[idx]); idx += 1

