public class Main {

    static final long mod = 1000000007;
    static HashMap&lt;Integer,Integer&gt; mp = new HashMap&lt;&gt;();
    static long ans = 1;

    static void divide(int x){
        for(int i=2;i*i&lt;=x;i++){
            int cnt=0;
            while(x%i==0){
                cnt++;
                x/=i;
            }
            if(cnt&gt;0){
